#!/usr/bin/env bash
# Prints all unique permutation of a given program as bash alias commands to stdout. Ideal for generation of "make" or "git" aliases.
# Usage:
# $ ./permute_aliases.sh <program> > ${XDG_CONFIG_HOME:-$HOME/.config}/shell/aliases_<program>
# source the generated file in you bash configuration file(s), like $(source aliases_<program>)
# or add it directly like
# $ ./permute_aliases.sh <program> >> ~/.bashrc

# Build counts per character and preserve first-seen character order.
_build_char_counts() {
	local input="$1"
	local -n out_counts="$2"
	local -n out_chars="$3"

	local i char
	for ((i = 0; i < ${#input}; i++)); do
		char="${input:i:1}"
		if [[ -z ${out_counts["$char"]+x} ]]; then
			out_counts["$char"]=0
			out_chars+=("$char")
		fi
		out_counts["$char"]=$((out_counts["$char"] + 1))
	done
}

# Emit all unique alias permutations directly.
_emit_permutations() {
	local program="$1"
	local target_len="$2"
	local prefix="$3"
	local depth="$4"
	local counts_name="$5"
	local chars_name="$6"
	local -n counts_ref="$counts_name"
	local -n chars_ref="$chars_name"

	if ((depth == target_len)); then
		if [[ "$prefix" != "$program" ]]; then
			printf "alias %s='%s'\n" "$prefix" "$program"
		fi
		return
	fi

	local char
	for char in "${chars_ref[@]}"; do
		if ((counts_ref["$char"] == 0)); then
			continue
		fi
		counts_ref["$char"]=$((counts_ref["$char"] - 1))
		_emit_permutations "$program" "$target_len" "${prefix}${char}" $((depth + 1)) "$counts_name" "$chars_name"
		counts_ref["$char"]=$((counts_ref["$char"] + 1))
	done
}

# Generate unique permutation aliases recursively.
permutate() {
	local program="$1"
	local -A counts=()
	local -a chars=()

	_build_char_counts "$program" counts chars
	_emit_permutations "$program" "${#program}" "" 0 counts chars
}

if [ "$#" -ne "1" ]; then
	echo "One argument expected: string to permute." 1>&2
	exit 1
else
	program="$1"
	echo "# Below follows all unique permutation aliases of \"${program}\", generated by \"${0##*/}\"."
	permutate "$program"
fi
